import{_ as t,a,b as n,c as l,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as r,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Telegram Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/telegram.md","filePath":"my/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"my/upload/telegram.md"};function h(p,e,m,b,g,u){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-channel-ထည့်သွင်းခြင်း" tabindex="-1">Telegram Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#telegram-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Telegram Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>အသုံးပြုရတဲ့အကြောင်း</th></tr></thead><tbody><tr><td>Telegram account</td><td>bot နဲ့ storage channel ဖန်တီးဖို့</td></tr><tr><td><code>@BotFather</code></td><td>Telegram bot ဖန်တီးဖို့</td></tr><tr><td>Telegram channel</td><td>files တွေကို သိမ်းမယ့် နောက်ဆုံးနေရာ</td></tr><tr><td><code>@userinfobot</code></td><td>channel <code>Chat ID</code> ရှာဖို့</td></tr></tbody></table><h2 id="ဘယ်နေရာမှာ-ထည့်မလဲ" tabindex="-1">ဘယ်နေရာမှာ ထည့်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-ထည့်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ ထည့်မလဲ&quot;">​</a></h2><ol><li>System Settings ကိုဖွင့်ပါ။</li><li>Upload Settings ကိုသွားပါ။</li><li>ညာဘက်အပေါ်ထောင့်က Add Channel ကိုနှိပ်ပါ။</li><li><code>Telegram</code> ကိုရွေးပါ။</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>အသုံးပြုပုံ</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ဒီ channel ကိုမှတ်မိလွယ်စေမယ့်အမည်၊ ဥပမာ <code>Telegram Primary</code>။</td><td>Required</td></tr><tr><td>Active</td><td>ဒီ channel ကို enable/disable လုပ်ရန်။</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Telegram bot ရဲ့ token။</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>Telegram channel ရဲ့ ID။</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Telegram access မတည်ငြိမ်တဲ့အခါပဲသုံးပါ။ <code>https://</code> ပါတဲ့ full proxy URL ထည့်ပါ။</td><td>Optional</td></tr><tr><td>Remark</td><td>နောက်ပိုင်း maintenance အတွက် မှတ်ချက်။</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-telegram-bot-ဖန်တီးပါ" tabindex="-1">1. Telegram Bot ဖန်တီးပါ <a class="header-anchor" href="#_1-telegram-bot-ဖန်တီးပါ" aria-label="Permalink to &quot;1. Telegram Bot ဖန်တီးပါ&quot;">​</a></h3><ol><li>Telegram ကိုဖွင့်ပြီး <code>@BotFather</code> ကိုရှာပါ။</li><li>chat ကိုဖွင့်ပြီး <code>Start</code> ကိုနှိပ်ပါ။</li><li><code>/newbot</code> ပို့ပါ။</li><li>prompt အတိုင်း bot display name ထည့်ပါ။</li><li>prompt အတိုင်း bot username ထည့်ပါ။ username က များသောအားဖြင့် <code>bot</code> နဲ့ဆုံးရပါမယ်။</li><li>bot ဖန်တီးပြီးရင် <code>@BotFather</code> က bot token ပြန်ပေးပါမယ်။</li></ol><p>ဒီ token ကို ImgBed ထဲက <code>Bot Token</code> မှာထည့်ရပါမယ်။</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-channel-ဖန်တီးပါ" tabindex="-1">2. Channel ဖန်တီးပါ <a class="header-anchor" href="#_2-channel-ဖန်တီးပါ" aria-label="Permalink to &quot;2. Channel ဖန်တီးပါ&quot;">​</a></h3><ol><li>Telegram မှာ New Channel ကိုနှိပ်ပါ။</li><li>channel name ထည့်ပါ။</li><li>channel ဖန်တီးမှုကိုပြီးအောင်လုပ်ပါ။</li></ol><p>public channel နဲ့ private channel နှစ်မျိုးလုံးသုံးနိုင်ပါတယ်။</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-bot-ကို-channel-ထဲထည့်ပါ" tabindex="-1">3. Bot ကို Channel ထဲထည့်ပါ <a class="header-anchor" href="#_3-bot-ကို-channel-ထဲထည့်ပါ" aria-label="Permalink to &quot;3. Bot ကို Channel ထဲထည့်ပါ&quot;">​</a></h3><ol><li>ဖန်တီးထားတဲ့ channel ကိုဖွင့်ပါ။</li><li>channel settings ကိုဖွင့်ပါ။</li><li>member သို့မဟုတ် administrator ထည့်တဲ့နေရာကိုဖွင့်ပါ။</li><li>ဖန်တီးထားတဲ့ bot username ကိုရှာပါ။</li><li>bot ကို channel ထဲထည့်ပါ။</li></ol><p>upload ပိုယုံကြည်စိတ်ချရအောင် bot ကို administrator permissions ပေးတာကောင်းပါတယ်။</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-user-info-get-id-idbot-ဖြင့်-channel-id-ရယူပါ" tabindex="-1">4. User Info - Get ID - IDbot ဖြင့် Channel ID ရယူပါ <a class="header-anchor" href="#_4-user-info-get-id-idbot-ဖြင့်-channel-id-ရယူပါ" aria-label="Permalink to &quot;4. User Info - Get ID - IDbot ဖြင့် Channel ID ရယူပါ&quot;">​</a></h3><ol><li>Telegram မှာ <code>@userinfobot</code> ကိုရှာပါ။ display name က များသောအားဖြင့် <code>User Info - Get ID - IDbot</code> ဖြစ်ပါတယ်။</li><li>chat ကိုဖွင့်ပြီး <code>Start</code> နှိပ်ပါ။</li><li>bot ပေးတဲ့ options ထဲက <code>Channel</code> ကိုရွေးပါ။</li><li>message picker ထဲမှာ target channel ကိုရွေးပြီး <code>@userinfobot</code> ကိုပို့ပါ။</li><li><code>@userinfobot</code> က result ပြန်ပေးရင် <code>Id: -100...</code> အနေနဲ့ပြထားတဲ့ number ကို copy လုပ်ပါ။</li></ol><p><code>-100</code> နဲ့စတဲ့ number က ImgBed မှာလိုအပ်တဲ့ <code>Session ID (Chat ID)</code> ဖြစ်ပါတယ်။</p><p><img src="'+l+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-imgbed-မှာ-telegram-channel-ဖြည့်ပါ" tabindex="-1">5. ImgBed မှာ Telegram Channel ဖြည့်ပါ <a class="header-anchor" href="#_5-imgbed-မှာ-telegram-channel-ဖြည့်ပါ" aria-label="Permalink to &quot;5. ImgBed မှာ Telegram Channel ဖြည့်ပါ&quot;">​</a></h3><p>channel configuration dialog ကိုပြန်သွားပြီး fields တွေကို ဒီလိုဖြည့်ပါ:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>custom channel name၊ ဥပမာ <code>TelegramPrimary</code>။</td></tr><tr><td>Active</td><td>Recommended။</td></tr><tr><td>Bot Token</td><td><code>@BotFather</code> ကရတဲ့ bot token။</td></tr><tr><td>Session ID (Chat ID)</td><td><code>@userinfobot</code> ကပြန်ပေးတဲ့ <code>-100...</code> number။</td></tr><tr><td>Relay Proxy URL (optional)</td><td>လိုအပ်မှသာ၊ ဥပမာ <code>https://your-tg-proxy.example.com</code>။</td></tr><tr><td>Remark</td><td>optional notes။</td></tr></tbody></table><p>ပြီးရင် Save ကိုနှိပ်ပါ။</p><p><img src="'+o+`" alt="Edit the configuration" loading="lazy"></p><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>စစ်ဆေးပုံ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save ပြီးနောက် Upload Settings မှာ Telegram channel card ပေါ်လာရပါမယ်။</td></tr><tr><td>Channel can be enabled</td><td>Active switch က on အနေအထားမှာရှိရပါမယ်။</td></tr><tr><td>Configuration is saved</td><td>detail view မှာ Bot Token နဲ့ Chat ID သိမ်းထားတာမြင်ရပါမယ်။</td></tr><tr><td>Upload works</td><td>test image တစ်ခု upload လုပ်ပြီး target Telegram channel ထဲပေါ်လာလားစစ်ပါ။</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather နဲ့ bot ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; Bot Token သိမ်းပါ</span></span>
<span class="line"><span>-&gt; Telegram channel ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; bot ကို channel ထဲထည့်ပြီး administrator permissions ပေးပါ</span></span>
<span class="line"><span>-&gt; @userinfobot ကိုရှာပြီး Channel ရွေးပါ</span></span>
<span class="line"><span>-&gt; channel ထဲက message တစ်ခုကို @userinfobot ဆီ forward လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ပြန်လာတဲ့ Id: -100... ကို copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed မှာ Bot Token နဲ့ Chat ID ထည့်ပါ</span></span>
<span class="line"><span>-&gt; Save လုပ်ပြီး test image upload လုပ်ပါ</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=d(c,[["render",h]]);export{_ as __pageData,T as default};
